var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아직 늦지 않았습니다!","JPN":"まだ間に合います！　","ENG":"It's not too late!","TWN":"現在還來得及！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"당장 추적해야 합니다, 사령관님!","JPN":"今すぐ追跡しなければ、司令官！","ENG":"We need to follow them, Commander!","TWN":"我們要立刻追擊，司令官！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"바보 같은 소리 말게, 도미닉.","JPN":"馬鹿を言うんじゃない、ドミニーク。","ENG":"Stop being so foolish, Dominic.","TWN":"別說傻話了，多明尼克。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"싸워 봤으니 잘 알겠지? 저들은 도망친 게 아니라 그저 물러났을 뿐이야.","JPN":"一度戦ってるし、わかるだろ？　あいつらは逃げたんじゃない、退却しただけだ。","ENG":"You fought them. They didn't run away; they left us.","TWN":"你和他們戰鬥過了，應該很清楚吧？他們不是逃跑，只是撤退而已。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지금 이 순간에도 우리의 퇴각로를 확보하기 위해 차원 폭풍 밖에서 제이크와 다른 동료들이 싸우고 있지.","JPN":"今この瞬間にも、次元の暴風の外ではジェイクらが我々の退却路を確保するために戦っている。","ENG":"And right now, Jake and the others are fighting outside this dimensional storm to secure a safe retreat route for us.","TWN":"現在這個當下，傑克和其他同伴們為了確保我們的退路，還在次元風暴外戰鬥著。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런데도 무리한 전투를 계속할 셈인가?","JPN":"それでも無謀な戦闘を続けるつもりか？","ENG":"Do you really want to ignore their struggle to go chase after them?","TWN":"即使如此，你還要繼續這種不合理的戰鬥嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다. 이번 작전은 실패로군요.","JPN":"了解しました。今回の作戦は失敗ですね。","ENG":"Understood. Looks like this operation has failed.","TWN":"我知道了。這次作戰失敗了呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"작전의 중요도에 비추어 볼 때, 저도 징계를 피하긴 힘들 겁니다.","JPN":"作戦の重要度からして、私も懲戒を免れないでしょう。","ENG":"Given its significance, there's no way I can avoid punishment.","TWN":"考慮到這次作戰的重要性，我應該也難逃處分吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"정보부에서 잘리게 되면 갈 곳이나 생각해 둬야겠군요.","JPN":"情報局をクビになった後のことを考えておかねば。","ENG":"Or stay at the Intelligence Agency for that matter. I'd better look for a new job.","TWN":"如果被情報部裁掉的話，我得想想還有什麼可以去的地方了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"고맙네. 자네가 앞으로 무슨 일을 하게 되든 내가 최선을 다해 돕도록 하지.","JPN":"すまない。君が今後どんな仕事に就こうとも、私が全力でバックアップするよ。","ENG":"Thank you. Wherever you go, I'll do my best to help you.","TWN":"謝謝你。無論你以後做什麼工作，我都會盡我的全力幫助你的。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......기대도 안 할 테니 훼방이나 놓지 마십시오.","JPN":"……それは望み薄だと思うので、どうかご放念を。","ENG":"No, thanks. Just stay out of my way.","TWN":"……我完全不期待，所以不要妨礙我。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"불길한 소리가 나는군. 나쁜 예감이 드는데?","JPN":"不吉な音だ。イヤな予感がするぞ。","ENG":"What's that ominous-sounding noise? It doesn't bode well for us.","TWN":"這什麼不祥的聲音，我有種不好的預感啊？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설마......?","JPN":"まさか……？","ENG":"Is it...","TWN":"難道……?"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이런! 함을 포위하고 있던 침식체들이 달려들고 있습니다!","JPN":"艦船を取り囲んでいた侵食体どもが暴れています！　","ENG":"Oh, no! The C.O.s around the ship—they're coming at us!","TWN":"天哪！包圍艦船的侵蝕體向這裡殺過來了！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아마도 함 내에 있던 불멸체 코어가 사라진 영향 때문인 것 같습니다!","JPN":"おそらく艦船内にいた不滅体コアが消えたせいかと！　","ENG":"Probably because the Immortal System Core is gone!","TWN":"大概是因為艦船內的不滅者核心消失造成的！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"불멸체 코어가 대체 뭐길래 저 녀석들이 흥분하는 거지?","JPN":"あいつらがあんなに暴れだすとは、いったい不滅体コアが何だと言うのだ？","ENG":"What the hell is that Immortal System Core that excites them so much?","TWN":"不滅者核心到底是什麼東西，讓這些傢伙這麼興奮啊？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저도 이유는 모릅니다. 하지만 침식체란 것들의 행동패턴은 단순하고 명확하죠.","JPN":"私も理由はわかりません。ただ、侵食体どもの行動パターンは単純明快です。","ENG":"I don't exactly know. But C.O.s are simple, intuitive creatures.","TWN":"我也不知道為什麼。但侵蝕體這種生物的行動模式，是簡單明確的。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};